function v = interpolate_image(C, method)
sz = size(C);
xg = 1:sz(1);
yg = 1:sz(2);
F = griddedInterpolant({xg,yg},double(C));
F.Method = method;
xq = (0:2.1:sz(1))';
yq = (0:2.1:sz(2))';
vq1 = F({xq,yq});

G = griddedInterpolant({xq,yq},double(vq1));
G.Method = 'nearest';

v = uint8(G({xg,yg}));

end

function [h, z] = cubic_spline_coefficients(t, y)
% [h, z] = cubic_spline_coefficients(t, y)
%
% Computes the solution z to the system of equations
%               Az = v
% where A is the tridiagonal system matrix for the cubic spline 
% interpolating polynomials with node points (t_n, y_n).
% Based on the pseudo-code on page 353 of Kincaid and
% Cheney.
%
% Input:
% t - the node points for the interpolation
% y - the value of interpolating function at the node points
%
% Output:
% z - the z_i coefficients in formula 7 on page 351
% h - the change in t, h_i = t_{i + 1} - t_i.  This is used in the
% evaluation of the cubic spline functions.

    n = length(y) - 1;

    % h and b are 0-indexed, this means we need to shift their indices in
    % the for-loops since 
    %               "h_0" = h(1), "h_1" = h(2)
    % and so forth in MATLAB.
    %
    % We can avoid these difficulties by using our tridiagonal solver
    % code from discussion and building the diagonal vectors directly.
    h = t(2 : end) - t(1 : end - 1);
    b = 6 * (y(2 : end) - y(1 : end - 1)) ./ h;
    
    % u and v are 1-indexed,
    u = zeros(1, n);
    v = zeros(size(u));
    
    u(1) = 2 * (h(1) + h(2));
    v(1) = (b(2) - b(1));

    % forward solve the tridiagonal system
    for i = 2 : n - 1
        % the indices for h and b are shifted because they start at 0
        u(i) = 2 * (h(i + 1) + h(i)) - (h(i))^2 / u(i - 1);
        v(i) = (b(i + 1) - b(i)) - h(i) * v(i - 1) / u(i - 1);
    end
    
    z = zeros(1, n);

    % back solve the tridiagonal system
    for i = n - 1 : -1 : 1
        z(i) = (v(i) - h(i + 1) * z(i + 1)) / u(i);
    end

    z = [0 z];
end

function yi = cubic_spline_direct(t, y, x)
% yi = cubic_spline_direct(t, y, x)
%
% Evaluates the cubic spline interpolating function, with node points t and
% y at the position x.  Based on the pseudo-code on page 350 to evaluate
% the correct cubic spline function and evaluates the cubic spline
% function, without using nested multipication, as defined in formula 7 on
% page 351.
%
% Input:
% t - the node points for the interpolation
% y - the value of interpolating function at the node points
% x - the position where we are evaluating the cubic spline function
%
% Output:
% yi - the value of the cubic spline at x

    [h, z] = cubic_spline_coefficients(t, y);
    n = length(y) - 1;
    index = 1;

    for i = 1 : n - 1
        if x < t(i + 1)
            break;
        end
        index = index + 1;
    end
    yi = z(index + 1) / (6 * h(index)) * (x - t(index))^3;
    yi = yi + z(index) / (6 * h(index)) * (t(index + 1) - x)^3;
    yi = yi + (y(index + 1) / h(index) - h(index) / 6 * z(index + 1)) * (x - t(index));
    yi = yi + (y(index) / h(index) - h(index) / 6 * z(index)) * (t(index + 1) - x);
end

function yi = cubic_spline(t, y, x)
% yi = cubic_spline(t, y, x)
%
% Evaluates the cubic spline interpolating function, with node points t and
% y at the position x.  Based on the pseudo-code on page 350 to evaluate
% the correct cubic spline function and evaluates the cubic spline
% function, using nested multipication, as defined by formula 11 on
% page 352.
%
% Input:
% t - the node points for the interpolation, listed in increasing order
% y - the value of interpolating function at the node points
% x - the position where we are evaluating the cubic spline function
%
% Output:
% yi - the value of the cubic spline at x

    [h, z] = cubic_spline_coefficients(t, y);

    n = length(y) - 1;
    index = 1;
    
    % with the terms in t increasing, we find i such that 
    %           t_i <= x < t_{i + 1}
    % by only checking the upper bound condition.
    for i = 1 : n - 1
        if x < t(i + 1)
            break;
        end
        index = index + 1;
    end
   
    A = 1 ./ (6 * h(index)) .* (z(index + 1) - z(index));
    B = z(index) / 2;
    tmp = - h(index) / 6 .* z(index + 1) - h(index) / 3 .* z(index);
    C = tmp + 1 / h(index) .* (y(index + 1) - y(index));
    dt = x - t(index);

    yi = y(index) + dt * (C + dt * (B + dt * A));
end

function yi = cubic_spline_vector(t, y, x)
% yi = cubic_spline(t, y, x)
%
% Evaluates the cubic spline interpolating function, with node points t and
% y at the positions in the vector x.  Based on the pseudo-code on page 350 
% to evaluate the correct cubic spline function and evaluates the cubic spline
% function, using nested multipication, as defined by formula 11 on
% page 352.
%
% Input:
% t - the node points for the interpolation, listed in increasing order
% y - the value of interpolating function at the node points
% x - the positions where we are evaluating the cubic
% spline function
%
% Output:
% yi - the value of the cubic spline at the positions defined by x    
    
    [h, z] = cubic_spline_coefficients(t, y);
    
    A = 1 ./ (6 * h) .* (z(2 : end) - z(1 : end - 1));
    B = z / 2;
    C = - h / 6 .* z(2 : end) - h / 3 .* z(1 : end - 1);
    C = C + 1 ./ h .* (y(2 : end) - y(1 : end - 1));
    
    n = length(y) - 1;
    index = ones(size(x));

    % With the terms in t increasing, we find i such that 
    %           t_i <= x < t_{i + 1}
    % by only checking the upper bound condition.  If we also assumed that
    % x is increasing we could assume that index(j) <= index(j + 1) and
    % reduce the number of comparisons made to find index(j + 1).
    for j = 1 : length(x)
        for i = 1 : n - 1
            if x(j) < t(i + 1)
                break;
            end
            index(j) = index(j) + 1;
        end
    end
    yi = y(index) + (x - t(index)) .* (C(index) + (x - t(index)) .* (B(index) + (x - t(index)) .* A(index)));  
end



function yi = tri_cubic_spline(t, y, x)
% yi = cubic_spline(t, y, x)
%
% Evaluates the cubic spline interpolating function, with node points t and
% y at the position x.  Based on the pseudo-code on page 350 to evaluate
% the correct cubic spline function and evaluates the cubic spline
% function, using nested multipication, as defined by formula 11 on
% page 352.
%
% Input:
% t - the node points for the interpolation, listed in increasing order
% y - the value of interpolating function at the node points
% x - the position where we are evaluating the cubic spline function
%
% Output:
% yi - the value of the cubic spline at x

    [h, z] = tri_cubic_spline_coefficients(t, y);

    n = length(y) - 1;
    index = 1;
    
    % with the terms in t increasing, we find i such that 
    %           t_i <= x < t_{i + 1}
    % by only checking the upper bound condition.
    for i = 1 : n - 1
        if x < t(i + 1)
            break;
        end
        index = index + 1;
    end
   
    A = 1 ./ (6 * h(index)) .* (z(index + 1) - z(index));
    B = z(index) / 2;
    tmp = - h(index) / 6 .* z(index + 1) - h(index) / 3 .* z(index);
    C = tmp + 1 / h(index) .* (y(index + 1) - y(index));
    dt = x - t(index);

    yi = y(index) + dt * (C + dt * (B + dt * A));
 
end

function [h, z] = tri_cubic_spline_coefficients(t, y)
% [h, z] = cubic_spline_tri(t, y)
%
% Computes the solution z to the system of equations
%               Az = v
% where A is the tridiagonal system matrix for the cubic spline 
% interpolating polynomials with node points (t_n, y_n).
% Based on the pseudo-code on page 353 of Kincaid and
% Cheney modified to use the code for solving tridiagonal 
% system of equations found on page 180.
%
% Input:
% t - the node points for the interpolation
% y - the value of interpolating function at the node points
%
% Output:
% z - the z_i coefficients in formula 7 on page 351
% h - the change in t, h_i = t_{i + 1} - t_i.  This is used in the
% evaluation of the cubic spline functions.
    n = length(y) - 1;

    % h and b are 0-indexed, this means we need to shift their indices in
    % the for-loops since 
    %               "h_0" = h(1), "h_1" = h(2)
    % and so forth in MATLAB.
    %
    % We can avoid these difficulties by using our tridiagonal solver
    % code from discussion and building the diagonal vectors directly.
    
    % the entries above and below the main diagonal, this vector is
    % 0-indexed
    h = t(2 : end) - t(1 : end - 1);
    b = 6 * (y(2 : end) - y(1 : end - 1)) ./ h;
    
    % the main diagonal of the system of equations
    u = 2 * (h(1 : end - 1) + h(2 : end));
    % the righthand side of the system of equations
    v = b(2 : end) - b(1 : end - 1);
    
    % We want to solve the system of equations with 
    % (h_1, h_2, ... , h_{n - 2}) above and below the main diagonal,
    % however h is 0-indexed so we need to adjust which terms we use.
    z = tri(h(2 : end), v, h(2 : end), u);  

    % z_0 = 0 and z_n = 0
    z = [0 z 0];
end


function x = tri(a, b, c, d)
% x = tri(a, b, c, d)
%
% Solves the n by n tridiagonal system of equations
%           A x = b
% where A's main diagonal is d, the diagonal above is c, and the diagonal
% below is a.  Based on the pseudo-code on page 180 of Kincaid and Cheney.
%
% Input:
% a - the entries of A that lie below the main diagonal.  Should be a
% vector of length n - 1
% b - the vector on the right hand side of the system of equations.  Should
% be a vector of length n
% c - the entries of A that lie above the main diagonal.  Should be a
% vector of length n - 1
% d - the entries of A that lie on the main diagonal.  Should be a vector
% of length n
%
% Output:
% x - the solution to the system of equations A x = b

    x = zeros(size(d));
    n = length(x);
    for i = 2 : n
        d(i) = d(i) - (a(i - 1) / d(i - 1)) * c(i - 1);
        b(i) = b(i) - (a(i - 1) / d(i - 1)) * b(i - 1);
    end
    
    x(n) = b(n) / d(n);

    for i = n - 1 : -1 : 1
        x(i) = (b(i) - c(i) * x(i + 1)) / d(i);
    end
end

function u = evaluate_newton_interpolant(x, y, t)
% u = evaluate_newton_interpolant(x, y, t)
%
% Horner's method for evaluating an interpolating polynomial in Newton's form
% at a position.  Based on the pseudo-code on page 311 from Kincaid and Cheney.
%
% Input:
% x - the nodes where the interpolation will occur
% y - the value of the function at the given node
% t - the position vector where we are evaluating the interpolating polynomial
%
% Output:
% u - u = p_k(t) -the value of the interpolating polynomial at the positions 
% described by t

    c = newton_interpolation_constants(x, y);
    u = zeros(size(t)) + c(end);
    
    % we have n + 1 points ranging from y0 to yn, so n is the length of y
    % minus 1
    n = length(y) - 1;
       
    % shift the index by 1 since MATLAB is 1-indexed
    for i = n : -1 : 1
        u = (t - x(i)) .* u + c(i);
    end
end

function c = newton_interpolation_constants(x, y)
% c = newton_interpolation_constants(x, y)
%
% Calculates the coefficients c_k of the Newton form of the
% interpolating polynomial p_k where
% p_k(x) = c0 + c1 (x - x0) + ... cn (x - x0)...(x - xn)
%
% Input:
%
% x - the nodes where the interpolation will occur
% y - the value of the function at the given node
%
% Output:
% c - the coefficients c_k of the interpolating polynomial

    c = zeros(size(y));
    c(1) = y(1);

    % we have n + 1 points ranging from x0 to xn, so n is the length of y
    % minus 1
    n = length(y) - 1;
    
    % shift the index by 1 since MATLAB is 1-indexed
    for k = 2 : n + 1
        d = x(k) - x(k - 1);
        u = c(k - 1);
        % shift only the final index from 0 to 1 since k - 2 has already
        % been shifted by 1 in the outer for-loop
        for i = k - 2 : -1 : 1
            u = u * (x(k) - x(i)) + c(i);
            d = d * (x(k) - x(i));
        end
        c(k) = (y(k) - u) / d;
    end
end

